from flask import Flask
from flask import jsonify
import requests  # requests lib required to handle HTTP request to flask app server for providing the topic name.
import os       # OS lib imported so that we can use environment variables. We will use the TOPIC_NAME variable in our code.
app = Flask(__name__)


@app.route("/<topic>")    ## Topic name to be received from http GET request on route: http://127.0.0.1:5000/topic-name
def main(topic):
    print("The topic is " + topic)      ## Printing for debugging. This can also be used as a sanity check that your code is working as intended or not
    import os
    from kafka import KafkaProducer

    producer = KafkaProducer(bootstrap_servers=os.environ['BROKER'])
    message = 'This is the message being published'     ## Message to be published in the topic. Any string of text can also work for this.
    producer.send(topic, bytes(message))   ## Sends a message as bytes. String in python 3.x would cause an error if sent via producer directly so we use bytes() to convert string to bytes type
    producer.flush()           ## Flushing the producer. This is necessary to make sure that all messages get published by kafka broker and not lost.

    return jsonify({"message": f"The message {message} in topic {topic} has been published successfully"})     # Returning a response of successful publish


if __name__ == "__main__":
    app.run(debug=True)